<!-- eslint-disable no-undef -->
<template>
  <div class="onboarding-container" :class="{ 'mobile-view': isMobile }">
    <div class="header">
      <div class="logo">
        <img src="/favicon.ico" alt="Pomelo" class="logo-img">
        <span class="logo-text">西柚 Pomelo</span>
      </div>
      <h2>Merchant Onboarding</h2>
      <p>Complete the form to join our platform</p>
    </div>
    
    <ProgressBar :currentStep="currentStep" :isMobile="isMobile" />
    
    <div class="form-section">
      <!-- 步骤1：商家信息 -->
      <div v-if="currentStep === 1">
        <h3>Business Information</h3>
        <p class="section-desc">Public-facing details about your business</p>
        
        <div class="section-divider"></div>
        
        <el-form ref="form" :model="form" :rules="rules" label-width="0">
          <el-row :gutter="20">
            <el-col :span="12" :xs="24">
              <el-form-item prop="merchantName" class="no-label">
                <div class="form-label">Business Name <span class="required">*</span></div>
                <el-input v-model="form.merchantName" placeholder="Enter your business name" maxlength="80"/>
                <div class="char-count">2-100 characters</div>
              </el-form-item>
            </el-col>
            <el-col :span="12" :xs="24">
              <el-form-item prop="merchantEnName" class="no-label">
                <div class="form-label">Business English Name</div>
                <el-input v-model="form.merchantEnName" placeholder="English name optional" maxlength="80"/>
                <div class="char-count">2-80 characters</div>
              </el-form-item>
            </el-col>
          </el-row>
          
          <el-form-item prop="merchantDesc" class="no-label">
                <div class="form-label">Business Introduction <span class="required">*</span></div>
                <el-input v-model="form.merchantDesc" type="textarea" placeholder="Brief description of your products or services" maxlength="300"/>
                <div class="char-count">{{ form.merchantDesc.length }}/300</div>
              </el-form-item>
          
          <el-row :gutter="20" class="logo-shop-row">
            <el-col :span="12">
              <el-form-item class="no-label">
                <div class="form-label">Business Logo</div>
                <div class="upload-box optimized">
                  <BigFileUpload 
                    @handleUploadSuccess="handleUploadSuccess"
                    :defaultUrl = "form.logo"
                    :imgWidth="screenWidth/4"
                    :imgHeight="130/200*screenWidth/4"
                    :flag="1"
                    :isOnlyShow="false"
                    :isMobile="isMobile"
                  />
                  <p class="upload-hint">PNG, JPG, JPEG up to 5MB</p>
                </div>
              </el-form-item>
            </el-col>
            <el-col :span="12">
              <el-form-item class="no-label">
                <div class="form-label">Shop Picture</div>
                <div class="upload-box optimized">
                  <BigFileUpload 
                    @handleUploadSuccess="handleUploadSuccess"
                    :defaultUrl = "form.shopImg"
                    :imgWidth="screenWidth/4"
                    :imgHeight="130/200*screenWidth/4"
                    :flag="2"
                    :isOnlyShow="false"
                    :isMobile="isMobile"
                  />
                  <p class="upload-hint">PNG, JPG, JPEG up to 5MB</p>
                </div>
              </el-form-item>
            </el-col>
          </el-row>
        </el-form>
      </div>
      
      <!-- 步骤2：服务信息 -->
      <div v-if="currentStep === 2">
        <h3>Service</h3>
        <p class="section-desc">School affiliation and representative details</p>
        
        <el-form ref="form" :model="form" :rules="rules">
          <el-row :gutter="20">
            <el-col :span="12" :xs="24">
              <el-form-item prop="deptId" class="no-label">
                <div class="form-label">Select School <span class="required">*</span></div>
                <el-select v-model="form.deptId" clearable placeholder="School of Engineering">
                  <el-option
                    v-for="item in deptList"
                    :key="item.deptId"
                    :label="item.deptName"
                    :value="item.deptId">
                  </el-option>
                </el-select>
              </el-form-item>
            </el-col>
            <el-col :span="12" :xs="24">
              <el-form-item prop="principalType" class="no-label">
                <div class="form-label">Principal Type <span class="required">*</span></div>
                <el-select v-model="form.principalType" clearable placeholder="Company" @change="handlePrincipalTypeChange">
                  <el-option
                    :key="1"
                    :label="'Person'"
                    :value="1">
                  </el-option>
                  <el-option
                    :key="2"
                    :label="'Company'"
                    :value="2">
                  </el-option>
                </el-select>
              </el-form-item>
            </el-col>
          </el-row>
          
          <el-row :gutter="20">
            <el-col :span="12" :xs="24">
              <el-form-item prop="representativeId" class="no-label">
                <div class="form-label">Authorized Representative ID <span class="required">*</span></div>
                <el-input v-model="form.representativeId" placeholder="321321" maxlength="50"/>
                <p class="char-count">8-50 characters</p>
              </el-form-item>
            </el-col>
            <el-col :span="12" :xs="24">
              <el-form-item prop="representativeName" class="no-label">
                <div class="form-label">Authorized Representative Name <span class="required">*</span></div>
                <el-input v-model="form.representativeName" placeholder="321321" maxlength="50"/>
                <p class="char-count">2-40 characters</p>
              </el-form-item>
            </el-col>
          </el-row>
          
          <el-row :gutter="20">
            <el-col :span="12" :xs="24">
              <el-form-item prop="ssn" class="no-label" v-if="form.principalType == '1' || form.principalType == 1">
                <div class="form-label">Social Security Number <span class="required">*</span></div>
                <el-input v-model="form.ssn" placeholder="Please input" maxlength="18"/>
              </el-form-item>
              <el-form-item prop="ein" class="no-label" v-if="form.principalType == '2' || form.principalType == 2">
                <div class="form-label">Employer Identification Number <span class="required">*</span></div>
                <el-input v-model="form.ein" placeholder="Please input" maxlength="18"/>
              </el-form-item>
            </el-col>
          </el-row>
        </el-form>
      </div>
      
      <!-- 步骤3：联系信息 -->
      <div v-if="currentStep === 3">
        <h3>Contact</h3>
        <p class="section-desc">Address & phones</p>
        
        <el-form ref="form" :model="form" :rules="rules">
          <el-form-item prop="merchantAddress" class="no-label">
            <div class="form-label">Shop Address <span class="required">*</span></div>
            <el-input v-model="form.merchantAddress" placeholder="77 Delancey St APT 3D, New York, NY 10002美国" maxlength="120" readonly>
              <template #append>
                <el-button @click="choseMap">Choose Address</el-button>
              </template>
            </el-input>
          </el-form-item>
          
          <el-row :gutter="20">
            <el-col :span="12">
              <el-form-item prop="zipcode" class="no-label">
                <div class="form-label">Zipcode</div>
                <el-input v-model="form.zipcode" placeholder="31232" maxlength="20"/>
              </el-form-item>
            </el-col>
            <el-col :span="12">
              <el-form-item prop="phonenumber" class="no-label">
                <div class="form-label">Phone Number</div>
                <el-input v-model="form.phonenumber" placeholder="1321321" maxlength="20"/>
              </el-form-item>
            </el-col>
          </el-row>
          
          <el-form-item prop="email" class="no-label">
            <div class="form-label">Email <span class="required">*</span></div>
            <el-input v-model="form.email" placeholder="321321@qq.com" maxlength="50"/>
          </el-form-item>
        </el-form>
      </div>
      
      <!-- 步骤4：账户信息 -->
      <div v-if="currentStep === 4">
        <h3>Account</h3>
        <p class="section-desc">Login credentials, banking and required documents</p>
        
        <el-form ref="form" :model="form" :rules="rules">
          <!-- 登录凭证 -->
          <div class="sub-section">
            <h4>LOGIN CREDENTIALS</h4>
            <el-form-item prop="userName" class="no-label">
              <div class="form-label">Login Username <span class="required">*</span></div>
              <el-input v-model="form.userName" placeholder="Your username" maxlength="30"/>
              <p class="char-count">3-30 characters, letters and numbers only</p>
            </el-form-item>
            
            <el-form-item prop="password" class="no-label">
              <div class="form-label">Login Password <span class="required">*</span></div>
              <el-input v-model="form.password" placeholder="Create a secure password" type="password" maxlength="20"/>
              <p class="char-count">Must include letters and numbers</p>
            </el-form-item>
          </div>
          
          <!-- 银行信息 -->
          <div class="sub-section">
            <h4>BANKING INFORMATION</h4>
            <el-form-item prop="bankName" class="no-label">
              <div class="form-label">Bank Name <span class="required">*</span></div>
              <el-input v-model="form.bankName" placeholder="e.g., Bank of America" maxlength="50"/>
            </el-form-item>
            
            <el-form-item prop="routingNumber" class="no-label">
              <div class="form-label">Routing Number <span class="required">*</span></div>
              <el-input v-model="form.routingNumber" placeholder="9 digits" maxlength="20"/>
              <p class="char-count">US ACH routing number</p>
            </el-form-item>
            
            <el-form-item prop="accountNumber" class="no-label">
              <div class="form-label">Account Number <span class="required">*</span></div>
              <el-input v-model="form.accountNumber" placeholder="6-17 digits" maxlength="30"/>
              <p class="char-count">Bank account number</p>
            </el-form-item>
            
            <el-form-item prop="accountHolderName" class="no-label">
              <div class="form-label">Account Holder Name <span class="required">*</span></div>
              <el-input v-model="form.accountHolderName" placeholder="Name on bank account" maxlength="50"/>
              <p class="char-count">2-50 characters</p>
            </el-form-item>
          </div>
          
          <!-- 所需文档 -->
          <div class="sub-section">
            <h4>REQUIRED DOCUMENTS</h4>
            <div class="document-upload-container">
              <div class="document-upload-item">
                <div class="form-label">Business Registration Document <span class="required">*</span></div>
                <div class="upload-box optimized">
                  <BigFileUpload 
                    @handleUploadSuccess="handleUploadSuccess"
                    :defaultUrl = "form.businessLicense"
                    :imgWidth="screenWidth/4"
                    :imgHeight="130/200*screenWidth/4"
                    :flag="3"
                    :isOnlyShow="false"
                    :isMobile="isMobile"
                  />
                  <p class="upload-hint">PDF, PNG, JPG, up to 10MB</p>
                </div>
              </div>
              <div class="document-upload-item">
                <div class="form-label">Permit License</div>
                <div class="upload-box optimized">
                  <BigFileUpload 
                    @handleUploadSuccess="handleUploadSuccess"
                    :defaultUrl = "form.permitLicense"
                    :imgWidth="screenWidth/4"
                    :imgHeight="130/200*screenWidth/4"
                    :flag="4"
                    :isOnlyShow="false"
                    :isMobile="isMobile"
                  />
                  <p class="upload-hint">PDF, PNG, JPG, up to 10MB</p>
                </div>
              </div>
            </div>
          </div>
        </el-form>
      </div>
      
      <!-- 按钮区域 -->
      <el-form-item class="form-buttons">
        <div class="left-buttons">
          <el-button class="save-draft-btn" @click="saveDraft(2);">Save Draft</el-button>
        </div>
        <div class="right-buttons">
          <el-button v-if="currentStep > 1" class="back-btn" @click="prevStep">{{leftStr}} Back</el-button>
          <el-button v-if="currentStep < 4" class="next-btn" @click="nextStep">Next ></el-button>
          <el-button v-if="currentStep === 4" class="next-btn" @click="submitForm">Next ></el-button>
        </div>
      </el-form-item>
    </div>
    
    <div class="footer-note">
      <p>Need help? Contact our support team at support@pomelo.com</p>
    </div>
    
    <!-- 地图选择对话框 -->
    <el-dialog
      title="Select Location"
      v-model="mapDialogVisible"
      :width="isMobile ? '90%' : '800px'"
    >
      <div style="height: 500px;">
        <!-- 搜索框 -->
        <div style="margin-bottom: 15px;">
          <el-input
            v-model="searchKeyword"
            placeholder="Please input keyword to search location (e.g., Times Square, New York)"
            @keyup.enter="searchLocation"
            clearable>
            <template #append>
              <el-button @click="searchLocation" :loading="searchLoading">Search</el-button>
            </template>
          </el-input>
        </div>
        
        <!-- Google地图容器 -->
        <div id="google-map" style="width: 100%; height: 350px; border: 1px solid #ddd;"></div>
        
        <!-- 地址信息显示 -->
        <div style="margin-top: 15px; padding: 15px; background-color: #f5f5f5; border-radius: 4px;">
          <el-form ref="mapForm" label-width="100px">
            <el-row :gutter="20">
              <el-col :span="24" :xs="24">
                <el-form-item label="Address:">
                  <el-input v-model="selectedAddress" placeholder="Please click on the map to select location or use search" readonly></el-input>
                </el-form-item>
              </el-col>
            </el-row>
            <el-row :gutter="20" :class="{ 'mobile-layout': isMobile }">
              <el-col :span="12" :xs="24" :class="{ 'full-width': isMobile }">
                <el-form-item label="Latitude:">
                  <el-input v-model="selectedLatitude" placeholder="Latitude" readonly></el-input>
                </el-form-item>
              </el-col>
              <el-col :span="12" :xs="24" :class="{ 'full-width': isMobile }">
                <el-form-item label="Longitude:">
                  <el-input v-model="selectedLongitude" placeholder="Longitude" readonly></el-input>
                </el-form-item>
              </el-col>
            </el-row>
          </el-form>
        </div>
      </div>
      <div class="dialog-footer">
        <el-button @click="closeMapDialog">Cancel</el-button>
        <el-button type="primary" @click="confirmMapSelection" :disabled="!selectedAddress">Confirm</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import ProgressBar from '../components/ProgressBar.vue';
import BigFileUpload from '../components/BigFileUpload.vue';

/* eslint-disable vue/multi-word-component-names */
/* eslint-disable no-undef */
export default {
  name: 'addMerchant',
  components: {
    ProgressBar,
    BigFileUpload
  },
  data() {
    return {
      leftStr: "<",
      currentStep: 1,
      mapDialogVisible: false,
      screenWidth: 0,
      // 表单数据
      form: {
        merchantName: '',
        merchantEnName: '',
        merchantDesc: '',
        logo: '',
        shopImg: '',
        deptId: '',
        principalType: '',
        representativeId: '',
        representativeName: '',
        ssn: '',
        ein: '',
        merchantAddress: '',
        zipcode: '',
        phonenumber: '',
        email: '',
        password: '',
        confirmPassword: '',
        bankName: '',
        accountHolderName: '',
        accountNumber: '',
        routingNumber: '',
        businessLicense: '',
        permitLicense: '',
        termsAgreed: false
      },
      
      // 验证规则
      rules: {
        merchantName: [{ required: true, message: 'Please enter business name', trigger: 'blur' }],
        deptId: [{ required: true, message: 'Please select school', trigger: 'change' }],
        principalType: [{ required: true, message: 'Please select principal type', trigger: 'change' }],
        representativeId: [{ required: true, message: 'Please enter authorized representative ID', trigger: 'blur' }],
        representativeName: [{ required: true, message: 'Please enter authorized representative name', trigger: 'blur' }],
        ssn: [{ required: true, message: 'Please enter social security number', trigger: 'blur' }],
        ein: [{ required: true, message: 'Please enter employer identification number', trigger: 'blur' }],
        merchantAddress: [{ required: true, message: 'Please select shop address', trigger: 'blur' }],
        email: [{ required: true, message: 'Please enter email', trigger: 'blur' }, { type: 'email', message: 'Please enter valid email', trigger: 'blur' }],
        password: [{ required: true, message: 'Please enter password', trigger: 'blur' }, { min: 6, message: 'Password must be at least 6 characters', trigger: 'blur' }],
        confirmPassword: [{ required: true, message: 'Please confirm password', trigger: 'blur' }, { validator: this.validatePassword, trigger: 'blur' }],
        bankName: [{ required: true, message: 'Please enter bank name', trigger: 'blur' }],
        accountHolderName: [{ required: true, message: 'Please enter account holder name', trigger: 'blur' }],
        accountNumber: [{ required: true, message: 'Please enter account number', trigger: 'blur' }],
        routingNumber: [{ required: true, message: 'Please enter routing number', trigger: 'blur' }],
        businessLicense: [{ required: true, message: 'Please upload business license', trigger: 'blur' }],
        permitLicense: [{ required: true, message: 'Please upload permit license', trigger: 'blur' }],
        termsAgreed: [{ required: true, message: 'Please agree to terms and conditions', trigger: 'change' }]
      },
      
      // 学校列表
      deptList: [],
      
      // 分类列表
      categoryList: [
        { dictCode: 'food', dictLabel: 'Food & Beverage' },
        { dictCode: 'retail', dictLabel: 'Retail' },
        { dictCode: 'service', dictLabel: 'Service' }
      ],
      
      // 子分类列表
      subCategoryList: [
        { dictCode: 'chinese', dictLabel: 'Chinese Food' },
        { dictCode: 'western', dictLabel: 'Western Food' },
        { dictCode: 'coffee', dictLabel: 'Coffee & Tea' }
      ],
      isMobile: false, // 初始化为非手机设备
      isTablet: false, // 初始化为非平板设备
      
      // 地图相关数据
      selectedAddress: '',
      selectedLatitude: '',
      selectedLongitude: '',
      map: null,
      marker: null,
      geocoder: null,
      mapLoading: false,
      // 搜索相关数据
      searchKeyword: '',
      searchLoading: false,
      placesService: null,
    };
  },
  mounted() {
    // 从sessionStorage加载数据
    this.loadFromSessionStorage();
    this.screenWidth = window.innerWidth;
    this.detectDevice();
    // 加载学校列表
    this.loadSchoolList();
  },
  methods: {
    // 加载学校列表
    loadSchoolList() {
      this.$axios.get(process.env.VUE_APP_API_BASE_URL + '/system/dept/schoolList')
        .then(response => {
          if (response.data && response.data.data) {
            this.deptList = response.data.data;
          }
        })
        .catch(error => {
          console.error('Failed to load school list:', error);
        });
    },
    
    // 处理Principal Type变化
    handlePrincipalTypeChange() {
      // 确保ssn和ein字段在切换类型时被清空
      if (this.form.principalType == '1' || this.form.principalType == 1) {
        this.form.ein = '';
      } else if (this.form.principalType == '2' || this.form.principalType == 2) {
        this.form.ssn = '';
      }
    },

    
    detectDevice() {
      const ua = navigator.userAgent;
      // 简单的正则表达式匹配，可以根据需要调整或增强这些规则
      //const isAndroid = ua.indexOf('Android') > -1; // Android平台
      const isIOS = ua.indexOf('like Mac OS X') > -1; // iOS平台，包括iPad等平板设备
      const isMobile = /Mobi|Android|Touch/i.test(ua); // 更通用的移动设备检测（包括平板和一些特殊情况）
      const isTablet = /Tablet/i.test(ua) && !isMobile; // 平板设备的检测（不包括移动设备）
      this.isMobile = isMobile || isIOS; // 根据需要设置手机或平板标志位
      this.isTablet = isTablet; // 设置平板标志位（如果需要的话）
    },
    // 验证密码
    validatePassword(rule, value, callback) {
      if (value !== this.form.password) {
        callback(new Error('Passwords do not match'));
      } else {
        callback();
      }
    },
    
    // 加载数据
    loadFromSessionStorage() {
      const businessData = sessionStorage.getItem('businessInfo');
      const serviceData = sessionStorage.getItem('serviceInfo');
      const contactData = sessionStorage.getItem('contactInfo');
      const accountData = sessionStorage.getItem('accountInfo');
      
      if (businessData) {
        Object.assign(this.form, JSON.parse(businessData));
      }
      if (serviceData) {
        Object.assign(this.form, JSON.parse(serviceData));
      }
      if (contactData) {
        Object.assign(this.form, JSON.parse(contactData));
      }
      if (accountData) {
        Object.assign(this.form, JSON.parse(accountData));
      }
    },
    
    // 保存草稿
    saveDraft(_type) {
      // 保存数据到sessionStorage
      sessionStorage.setItem('businessInfo', JSON.stringify(this.form));
      sessionStorage.setItem('serviceInfo', JSON.stringify(this.form));
      sessionStorage.setItem('contactInfo', JSON.stringify(this.form));
      sessionStorage.setItem('accountInfo', JSON.stringify(this.form));
      
      if(_type == 2){
        this.$message.success('Draft saved successfully!');
      }
    },
    
    // 上一步
    prevStep() {
      // 保存当前步骤数据
      this.saveDraft(1);
      this.currentStep--;
    },
    
    // 下一步
    nextStep() {
      // 验证当前步骤表单
      this.$refs.form.validate((valid) => {
        if (valid) {
          // 保存当前步骤数据
          this.saveDraft(1);
          this.currentStep++;
        }
      });
    },
    
    // 提交表单
    submitForm() {
      this.$refs.form.validate((valid) => {
        if (valid) {
          // 保存当前表单数据
          //this.saveDraft();
          
          // 调用API接口
          this.$axios.post(process.env.VUE_APP_API_BASE_URL + '/app/merchant/addMerchant', this.form)
            .then(response => {
              if (response.data.code === 200) {
                this.$message.success('Merchant added successfully!');
                // 跳转到成功页面
                this.$router.push('/success');
              } else {
                this.$message.error('Failed to add merchant: ' + response.data.message);
              }
            })
            .catch(error => {
              console.error('API call failed:', error);
              this.$message.error('Network error, please try again later');
            });
        }
      });
    },
    
    // 处理文件上传成功的回调
    handleUploadSuccess(response, flag) {
      // 处理文件上传成功的回调
      console.log('File uploaded successfully:', response, flag);
      switch(flag) {
        case 1:
          this.form.logo = response.url || response.path || response;
          break;
        case 2:
          this.form.shopImg = response.url || response.path || response;
          break;
        case 3:
          this.form.businessLicense = response.url || response.path || response;
          break;
        case 4:
          this.form.permitLicense = response.url || response.path || response;
          break;
      }
    },
    
    // 选择地图
    choseMap() {
      this.mapDialogVisible = true;
      this.$nextTick(() => {
        this.initGoogleMap();
      });
    },
    
    // 初始化Google地图
    initGoogleMap() {
      // 检查Google Maps API是否已加载
      if (window.google && window.google.maps) {
        this.createMap();
        return;
      }

      // 检查是否已经在加载中
      if (this.mapLoading) {
        return;
      }
      this.mapLoading = true;

      // 动态加载Google Maps API
      const script = document.createElement('script');
      script.src = `https://maps.googleapis.com/maps/api/js?key=AIzaSyA8l6T6nQmrR9JIFHGnq9mgrOGYCzT8aEg&libraries=places&callback=initGoogleMapCallback_${Date.now()}`;
      script.async = true;
      script.defer = true;
      
      // 生成唯一的回调函数名
      const callbackName = `initGoogleMapCallback_${Date.now()}`;
      
      // 设置全局回调函数
      window[callbackName] = () => {
        try {
          this.createMap();
          // 清理回调函数
          delete window[callbackName];
        } catch (error) {
          console.error('Google Maps初始化失败:', error);
          this.$message.error('地图初始化失败');
        } finally {
          this.mapLoading = false;
        }
      };
      
      script.onerror = () => {
        console.error('Google Maps API加载失败');
        this.$message.error('地图加载失败，请检查网络连接');
        this.mapLoading = false;
        // 清理回调函数
        delete window[callbackName];
      };
      
      document.head.appendChild(script);
    },

    // 创建地图实例
    createMap() {
      try {
        // 检查地图容器是否存在
        const mapElement = document.getElementById("google-map");
        if (!mapElement) {
          console.error('地图容器不存在');
          this.$message.error('地图容器不存在');
          return;
        }

        // 检查Google Maps API是否可用
        if (!window.google || !window.google.maps) {
          console.error('Google Maps API未加载');
          this.$message.error('Google Maps API未加载');
          return;
        }

        // 默认中心位置（可以设置为用户当前位置或其他默认位置）
        const defaultCenter = { lat: 40.7128, lng: -74.0060 }; // 纽约市
        
        // 创建地图实例
        this.map = new google.maps.Map(mapElement, {
          center: defaultCenter,
          zoom: 13,
          mapTypeControl: true,
          streetViewControl: true,
          fullscreenControl: true,
          zoomControl: true,
          gestureHandling: 'greedy', // 允许单手操作
        });

      // 创建地理编码器
      this.geocoder = new google.maps.Geocoder();

      // 创建Places服务
      this.placesService = new google.maps.places.PlacesService(this.map);

      // 创建标记
      this.marker = new google.maps.Marker({
        position: defaultCenter,
        map: this.map,
        draggable: true,
        title: "Drag to select location",
        animation: google.maps.Animation.DROP
      });

        // 监听地图点击事件
        this.map.addListener('click', (event) => {
          this.handleMapClick(event.latLng);
        });

        // 监听标记拖拽事件
        this.marker.addListener('dragend', (event) => {
          this.handleMarkerDrag(event.latLng);
        });

        // 初始化时获取默认位置的地址信息
        this.getAddressFromLatLng(defaultCenter);

      console.log('Google Maps初始化成功');

    } catch (error) {
      console.error('Google Maps创建失败:', error);
      this.$message.error('地图创建失败: ' + error.message);
    }
  },

  // 搜索位置
  searchLocation() {
    if (!this.searchKeyword.trim()) {
      this.$message.warning('Please input search keyword');
      return;
    }

    if (!this.geocoder) {
      this.$message.error('地图服务未初始化');
      return;
    }

    this.searchLoading = true;

    // 使用地理编码器搜索位置
    this.geocoder.geocode({
      address: this.searchKeyword,
      region: 'cn' // 优先搜索中国地区
    }, (results, status) => {
      this.searchLoading = false;

      if (status === 'OK' && results && results.length > 0) {
        const location = results[0].geometry.location;
        const latLng = { lat: location.lat(), lng: location.lng() };

        // 移动地图到搜索结果位置
        this.map.panTo(latLng);
        this.map.setZoom(15);

        // 更新标记位置
        this.marker.setPosition(latLng);

        // 获取地址信息
        this.getAddressFromLatLng(latLng);

        this.$message.success('Search successful');
      } else {
        console.error('搜索失败:', status);
        this.$message.error('Search failed, please check keyword or network connection');
      }
    });
  },

    // 处理地图点击事件
    handleMapClick(latLng) {
      const lat = latLng.lat();
      const lng = latLng.lng();
      
      // 更新标记位置
      this.marker.setPosition(latLng);
      
      // 更新地图中心
      this.map.panTo(latLng);
      
      // 获取地址信息
      this.getAddressFromLatLng({ lat, lng });
    },

    // 处理标记拖拽事件
    handleMarkerDrag(latLng) {
      const lat = latLng.lat();
      const lng = latLng.lng();
      
      // 更新地图中心
      this.map.panTo(latLng);
      
      // 获取地址信息
      this.getAddressFromLatLng({ lat, lng });
    },

    // 根据经纬度获取地址信息
    getAddressFromLatLng(latLng) {
      if (!this.geocoder) {
        console.error('地理编码器未初始化');
        this.selectedAddress = 'Geocoder not initialized';
        this.selectedLatitude = latLng.lat.toFixed(6);
        this.selectedLongitude = latLng.lng.toFixed(6);
        return;
      }

      this.geocoder.geocode({ location: latLng }, (results, status) => {
        if (status === 'OK' && results && results[0]) {
          this.selectedAddress = results[0].formatted_address;
          this.selectedLatitude = latLng.lat.toFixed(6);
          this.selectedLongitude = latLng.lng.toFixed(6);
          console.log('地址解析成功:', results[0].formatted_address);
        } else {
          console.error('地理编码失败:', status);
          this.selectedAddress = 'Unable to get address information';
          this.selectedLatitude = latLng.lat.toFixed(6);
          this.selectedLongitude = latLng.lng.toFixed(6);
        }
      });
    },

    // 确认地图选择
    confirmMapSelection() {
      if (this.selectedAddress && this.selectedLatitude && this.selectedLongitude) {
        // 将选择的位置信息保存到表单中
        this.form.merchantAddress = this.selectedAddress;
        this.form.latitude = this.selectedLatitude;
        this.form.longitude = this.selectedLongitude;
        
        this.$message.success('Location selected successfully');
        this.closeMapDialog();
      } else {
        this.$message.warning('Please select a location on the map first');
      }
    },

    // 关闭地图弹窗
    closeMapDialog() {
      this.mapDialogVisible = false;
      this.resetMapData();
    },

  // 重置地图数据
  resetMapData() {
    // 重置地图数据
    this.selectedAddress = '';
    this.selectedLatitude = '';
    this.selectedLongitude = '';
    this.mapLoading = false;
    this.searchKeyword = '';
    this.searchLoading = false;
    
    // 清理地图实例
    this.cleanupMap();
  },

    // 清理地图实例
    cleanupMap() {
      try {
        if (this.marker) {
          this.marker.setMap(null);
          this.marker = null;
        }
        if (this.map) {
          // 清除地图事件监听器
          google.maps.event.clearInstanceListeners(this.map);
          this.map = null;
        }
        if (this.geocoder) {
          this.geocoder = null;
        }
        this.placesService = null;
        console.log('地图实例已清理');
      } catch (error) {
        console.error('清理地图实例时出错:', error);
      }
    }
  }
};
</script>

